import Foundation
import MusiccloudApiClient

enum ConfigurationError: LocalizedError {
  case missingApiKey

  var errorDescription: String? {
    "MUSICCLOUD_API_KEY is required."
  }
}

func musiccloudApiKey() throws -> String {
  guard
    let apiKey = ProcessInfo.processInfo.environment["MUSICCLOUD_API_KEY"],
    !apiKey.isEmpty
  else {
    throw ConfigurationError.missingApiKey
  }
  return apiKey
}

let configuration = MusiccloudApiClientAPIConfiguration(
  customHeaders: ["X-API-Key": try musiccloudApiKey()]
)

quickstart.firstRequest:
let request = ApiV1ResolvePostRequest(
  query: "https://open.spotify.com/track/example"
)
let result = try await ResolveAPI.apiV1ResolvePost(
  apiV1ResolvePostRequest: request,
  apiConfiguration: configuration
)
print(result)
